    " \' หากพ้นกำหนดแล้ว\'";
            this.paragraph_2.Name = "paragraph_2";
            // 
            // paragraph_3
            // 
            this.paragraph_3.DataMember = "Query";
            this.paragraph_3.Expression = "[RESSET_NO]+\' ลงวันที่ \'+[RES_DATE]+\' มีมติให้ท่านพ้นจากการเป็นสมาชิกตามระเบียบแล" +
    "ะข้อบังคับของสหกรณ์\'";
            this.paragraph_3.Name = "paragraph_3";
            // 
            // paragraph_4
            // 
            this.paragraph_4.DataMember = "Query";
            this.paragraph_4.Expression = "\'ซึ่ง ณ วันที่ \'+[BALANCE_DATE]+\' ท่านมีทุนเรือนหุ้นและหนี้คงเหลือ ดังนี้\'";
            this.paragraph_4.Name = "paragraph_4";
            // 
            // paragraph_5
            // 
            this.paragraph_5.DataMember = "Query";
            this.paragraph_5.Expression = "\'\tตามที่ \'+[MEMBER_NAME] + \' ได้กู้เงินไปจากสหกรณ์ฯ จำนวน \' + [LOAN_APPROVE_AMOUN" +
    "T] + \' บาท\'";
            this.paragraph_5.Name = "paragraph_5";
            // 
            // paragraph_6
            // 
            this.paragraph_6.DataMember = "Query";
            this.paragraph_6.Expression = "\'ตามหนังสือเงินกู้สามัญ เลขที่ \' + [LOAN_CONTRACT_NO] + \' ลงฉบับวันที่ \' + [BEGIN" +
    "ING_OF_CONTRACT] + \' โดยมีท่านผูกพันตนเข้า\'";
            this.paragraph_6.Name = "paragraph_6";
            // 
            // paragraph_7
            // 
            this.paragraph_7.DataMember = "Query";
            this.paragraph_7.Expression = "\'โดยมติที่ประชุมคณะกรรมการดำเนินการสหกรณ์  ชุดที่  \'+[RES_NO]+\'  ครั้งที่  \'+[RES" +
    "SET_NO]+\'  ลงวันที่  \'+[RES_DATE]+\'  มีมติ\'";
            this.paragraph_7.Name = "paragraph_7";
            // 
